Hello,

In case someone wants to achieve this, I succeeded doing it using Buffers (which could be quite easily converted to Stream). Here is my code.

```
/* Reading */
let buffer: Buffer;
let workbook = await ExcelService.getWorkbookFromBuffer(buffer);

/* Editing */
let worksheet = workbook.getWorksheet(1);
let row = worksheet.getRow(1);
row.getCell(1).value = "Test";
row.commit();

/* Writing */
let result: Buffer = await workbook.xlsx.writeBuffer();  
```       

and ExcelService.ts :  

```
export class ExcelService {

    public static async getWorkbookFromBuffer(buffer: Buffer): Promise<any> {
        return new Promise((resolve, reject) => {
            try {
                const workbook = new Excel.Workbook();
                const readStream = new stream.PassThrough();
                const writeStream = workbook.xlsx.createInputStream();
                readStream.end(buffer);
                readStream.pipe(writeStream);

                writeStream.on('done', () => {
                    resolve(workbook)
                })

                readStream.on('end', () => {
                    //writeStream.end()
                })

                readStream.on('data', chunk => {
                    writeStream.write(chunk)
                })
            }
            catch (e) {
                reject(e);
            }
        });
    }
}
```
